#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ull unsigned long long
const int N=300005,base=31;
string s;
int n,a[N],b[N];
ull has[N],tmp[N];
ull hasnum(int l,int r)
{
	return has[r]-has[l-1]*tmp[r-l+1];
}
int fun(int x,int y)
{
	int l=-1,r=min(n-x+1,n-y+1)+1;
	while(l<=r)
	{
		int mid=(l+r)/2;
		if(hasnum(x,x+mid-1)==hasnum(y,y+mid-1)) l=mid+1;
		else r=mid-1;
	}
	return l-1;
}
bool cmp(int x,int y)
{
	int num=fun(x,y);
	return s[x+num]<s[y+num];
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>s;
	n=s.size();
	s=" "+s;
	tmp[0]=1;
	for(int i=1;i<=n;i++)
	{
		a[i]=i;
		tmp[i]=tmp[i-1]*base;
		has[i]=has[i-1]*base+s[i]-'a';
	}
	sort(a+1,a+1+n,cmp);
	for(int i=1;i<=n;i++) cout<<a[i]-1<<" ";
	cout<<"\n";
	for(int i=1;i<=n;i++) cout<<fun(a[i],a[i-1])<<" ";
	return 0;
}
